const addImagesToMovements = (movements: Movement[]): Movement[] => {
  return movements.map(movement => ({
    ...movement,
    image: exerciseImages[movement.name] || undefined,
  }));
};

const addImagesToSessions = (sessions: Session[]): Session[] => {
  return sessions.map(session => ({
    ...session,
    movements: addImagesToMovements(session.movements),
  }));
};

